sp_widget.client_script:
function SelfRegController($window) {
    var c = this;
    c.form = {};

    c.registerUser = function() {
        c.error = null;
        c.success = null;

        // Trigger the internal server script data flow
        c.server.get({
            action: 'register_citizen',
            name: c.form.name,
            email: c.form.email,
            password: c.form.password
        }).then(function(response) {
            if (response.data.success) {
                c.success = "Account created successfully! Redirecting you to the login screen...";

                $window.setTimeout(function() {
                    $window.location.href = "/sp?id=login";
                }, 1500);
            } else {
                c.error = response.data.error || "Registration rejected by server.";
            }
        });
    };
}

sp_widget.script:
(function() {
    if (input && input.action === 'register_citizen') {
        data.success = false;
        data.error = null;

        // 1. Check if the user email already exists
        var checkUser = new GlideRecord('sys_user');
        checkUser.addQuery('email', input.email);
        checkUser.query();
        if (checkUser.hasNext()) {
            data.error = "This email address is already registered.";
            return;
        }

        // 2. Initialize and create the new user record securely
        var userGr = new GlideRecord('sys_user');
        userGr.initialize();

        // Parse out first name and last name cleanly
        var nameParts = input.name.split(' ');
        userGr.first_name = nameParts[0] || input.name;
        userGr.last_name = nameParts.slice(1).join(' ') || '.';

        userGr.email = input.email;
        userGr.user_name = input.email; // Sets login username to email address

        // FIX: Force ServiceNow to invoke its native credential encryption hashing engine
        userGr.user_password.setDisplayValue(input.password); 
        userGr.active = true;

        var newUserSysId = userGr.insert();

        if (newUserSysId) {
            // 3. Grant the mandatory external user role
            var roleGr = new GlideRecord('sys_user_has_role');
            roleGr.initialize();
            roleGr.user = newUserSysId;
            roleGr.role.setDisplayValue('snc_external');
            roleGr.insert();

            data.success = true;
        } else {
            data.error = "Database rejected user row allocation. Check application cross-scope tables.";
        }
    }
})();
